        if _, err := r.runtimeClient.Version(ctx, &runtimeapi.VersionRequest{}); err != nil {
                return fmt.Errorf("validate CRI v1 runtime API for endpoint %q: %w", endpoint, err)
        }

        r.log(2, "Validated CRI v1 runtime API")
        return nil
}

